define i32 @smul_overflow(i32 %a, i32 %b) {
  %val = tail call { i32, i1 } @llvm.smul.with.overflow.i32(i32 %a, i32 %b)
  %ov = extractvalue { i32, i1 } %val, 1
  tail call void @llvm.assume(i1 %ov)
  %res = extractvalue { i32, i1 } %val, 0
  ret i32 %res
}

